from __future__ import annotations
from dataclasses import dataclass, field
from enum import Enum, auto
from typing import Optional


# ── Signal Values ─────────────────────────────────────────────────────

class Signal(Enum):
    """Digital signal levels."""
    LOW = 0
    HIGH = 1

    def __invert__(self) -> Signal:
        return Signal.LOW if self == Signal.HIGH else Signal.HIGH

    def __and__(self, other: Signal) -> Signal:
        return Signal(self.value & other.value)

    def __or__(self, other: Signal) -> Signal:
        return Signal(self.value | other.value)

    def __xor__(self, other: Signal) -> Signal:
        return Signal(self.value ^ other.value)

    def __repr__(self) -> str:
        return str(self.value)


L, H = Signal.LOW, Signal.HIGH


# ── Wire: connects gate outputs to gate inputs ───────────────────────

@dataclass
class Wire:
    """A named wire carrying a digital signal."""
    name: str
    signal: Signal = Signal.LOW
    delay: int = 0

    def __repr__(self) -> str:
        return f"Wire({self.name}={self.signal.value}, d={self.delay})"


# ── Gate base class ───────────────────────────────────────────────────

@dataclass
class Gate:
    """Abstract base class for all logic gates."""
    name: str
    inputs: list[Wire] = field(default_factory=list)
    output: Wire = field(default_factory=lambda: Wire("out"))

    def evaluate(self) -> Signal:
        raise NotImplementedError

    def propagate(self) -> Signal:
        self.output.signal = self.evaluate()
        self.output.delay = max(w.delay for w in self.inputs) + 1
        return self.output.signal

    def __repr__(self) -> str:
        ins = ", ".join(f"{w.name}={w.signal.value}" for w in self.inputs)
        return f"{type(self).__name__}({self.name}: [{ins}] -> {self.output.signal.value})"


# ── NAND gate (primitive) ─────────────────────────────────────────────

class NANDGate(Gate):
    """NAND gate: output is LOW only when ALL inputs are HIGH."""

    def evaluate(self) -> Signal:
        result = Signal.HIGH
        for w in self.inputs:
            result = result & w.signal
        return ~result


# ── Composite Gate ────────────────────────────────────────────────────

class CompositeGate(Gate):
    """A gate composed of internal sub-gates."""

    def __init__(self, name: str, inputs: list[Wire] | None = None):
        super().__init__(name=name, inputs=inputs if inputs is not None else [])
        self.internal_gates: list[Gate] = []
        self.internal_wires: list[Wire] = []
        self._build_internals()

    def _build_internals(self) -> None:
        raise NotImplementedError

    def evaluate(self) -> Signal:
        for gate in self.internal_gates:
            gate.propagate()
        return self.output.signal

    def propagate(self) -> Signal:
        self.evaluate()
        self.output.delay = max(
            (g.output.delay for g in self.internal_gates), default=0
        )
        return self.output.signal

    @property
    def gate_count(self) -> int:
        count = 0
        for g in self.internal_gates:
            if isinstance(g, CompositeGate):
                count += g.gate_count
            else:
                count += 1
        return count


# ── NOT gate from NAND ────────────────────────────────────────────────

class NOTGate(CompositeGate):
    """NOT(x) = NAND(x, x). Uses 1 NAND gate."""

    def _build_internals(self) -> None:
        a = self.inputs[0]
        nand = NANDGate(name=f"{self.name}_nand0", inputs=[a, a])
        self.internal_gates.append(nand)
        self.output = nand.output


# ── AND gate from NAND ────────────────────────────────────────────────

class ANDGate(CompositeGate):
    """AND(a, b) = NOT(NAND(a, b)). Uses 2 NAND gates."""

    def _build_internals(self) -> None:
        a, b = self.inputs[0], self.inputs[1]
        # First NAND: NAND(a, b)
        nand1 = NANDGate(name=f"{self.name}_nand0", inputs=[a, b])
        # Second NAND acts as NOT: NAND(nand1_out, nand1_out)
        nand2 = NANDGate(
            name=f"{self.name}_nand1",
            inputs=[nand1.output, nand1.output],
        )
        self.internal_gates.extend([nand1, nand2])
        self.output = nand2.output


# ── OR gate from NAND ─────────────────────────────────────────────────

class ORGate(CompositeGate):
    """OR(a, b) = NAND(NOT(a), NOT(b)). Uses 3 NAND gates."""

    def _build_internals(self) -> None:
        a, b = self.inputs[0], self.inputs[1]
        # NOT(a) = NAND(a, a)
        not_a = NANDGate(name=f"{self.name}_not_a", inputs=[a, a])
        # NOT(b) = NAND(b, b)
        not_b = NANDGate(name=f"{self.name}_not_b", inputs=[b, b])
        # OR = NAND(NOT(a), NOT(b))
        nand_final = NANDGate(
            name=f"{self.name}_nand_final",
            inputs=[not_a.output, not_b.output],
        )
        self.internal_gates.extend([not_a, not_b, nand_final])
        self.output = nand_final.output


# ── XOR gate from NAND ────────────────────────────────────────────────

class XORGate(CompositeGate):
    """XOR(a, b) = NAND(NAND(a, NAND(a,b)), NAND(b, NAND(a,b))). Uses 4 NAND gates."""

    def _build_internals(self) -> None:
        a, b = self.inputs[0], self.inputs[1]
        # Gate 1: NAND(a, b)
        g1 = NANDGate(name=f"{self.name}_g1", inputs=[a, b])
        # Gate 2: NAND(a, g1_out)
        g2 = NANDGate(name=f"{self.name}_g2", inputs=[a, g1.output])
        # Gate 3: NAND(b, g1_out)
        g3 = NANDGate(name=f"{self.name}_g3", inputs=[b, g1.output])
        # Gate 4: NAND(g2_out, g3_out)
        g4 = NANDGate(name=f"{self.name}_g4", inputs=[g2.output, g3.output])
        self.internal_gates.extend([g1, g2, g3, g4])
        self.output = g4.output


# ── Simulation Engine ─────────────────────────────────────────────────

class CircuitSimulator:
    """Simulate a circuit defined as a list of gates."""

    def __init__(self, name: str):
        self.name = name
        self.gates: list[Gate] = []
        self.input_wires: list[Wire] = []
        self.output_wires: list[Wire] = []

    def add_input(self, name: str) -> Wire:
        wire = Wire(name, delay=0)
        self.input_wires.append(wire)
        return wire

    def add_gate(self, gate: Gate) -> Gate:
        self.gates.append(gate)
        return gate

    def add_output(self, wire: Wire) -> None:
        self.output_wires.append(wire)

    def set_inputs(self, values: dict[str, Signal]) -> None:
        for wire in self.input_wires:
            if wire.name in values:
                wire.signal = values[wire.name]
                wire.delay = 0

    def simulate(self) -> dict[str, Signal]:
        for gate in self.gates:
            gate.propagate()
        return {w.name: w.signal for w in self.output_wires}

    @property
    def propagation_delay(self) -> int:
        if not self.output_wires:
            return 0
        return max(w.delay for w in self.output_wires)

    @property
    def total_gate_count(self) -> int:
        count = 0
        for g in self.gates:
            if isinstance(g, CompositeGate):
                count += g.gate_count
            else:
                count += 1
        return count

    def verify_truth_table(
        self,
        input_names: list[str],
        output_name: str,
        expected: list[tuple[list[int], int]],
    ) -> list[dict]:
        results = []
        for input_vals, exp_out in expected:
            values = {
                name: Signal(val)
                for name, val in zip(input_names, input_vals)
            }
            self.set_inputs(values)
            outputs = self.simulate()
            actual = outputs[output_name].value
            results.append({
                "inputs": dict(zip(input_names, input_vals)),
                "expected": exp_out,
                "actual": actual,
                "passed": actual == exp_out,
            })
        return results


def build_gate_circuit(
    gate_class: type,
    input_names: list[str],
    gate_name: str = "g0",
) -> tuple[CircuitSimulator, Gate]:
    """Create a single-gate circuit for testing."""
    sim = CircuitSimulator(f"{gate_class.__name__}_test")
    wires = [sim.add_input(n) for n in input_names]
    gate = gate_class(name=gate_name, inputs=wires)
    sim.add_gate(gate)
    sim.add_output(gate.output)
    return sim, gate

