class ORGate(CompositeGate):
    def _build_internals(self) -> None:
        a, b = self.inputs[0], self.inputs[1]
        na = NANDGate(name=f"{self.name}_na", inputs=[a, a])
        nb = NANDGate(name=f"{self.name}_nb", inputs=[b, b])
        nf = NANDGate(name=f"{self.name}_nf", inputs=[na.output, nb.output])
        self.internal_gates.extend([na, nb, nf])
        self.output = nf.output

class XORGate(CompositeGate):
    def _build_internals(self) -> None:
        a, b = self.inputs[0], self.inputs[1]
        g1 = NANDGate(name=f"{self.name}_g1", inputs=[a, b])
        g2 = NANDGate(name=f"{self.name}_g2", inputs=[a, g1.output])
        g3 = NANDGate(name=f"{self.name}_g3", inputs=[b, g1.output])
        g4 = NANDGate(name=f"{self.name}_g4", inputs=[g2.output, g3.output])
        self.internal_gates.extend([g1, g2, g3, g4])
        self.output = g4.output


# ── ALU Operation Codes ───────────────────────────────────────────────

class ALUOp(Enum):
    ADD = 0
    SUB = 1
    AND = 2
    OR  = 3
    XOR = 4
    SLT = 5


# ── Half Adder ────────────────────────────────────────────────────────

class HalfAdder:
    """sum = a XOR b, carry = a AND b."""

    def __init__(self, name: str = "ha"):
        self.name = name
        self.a = Wire(f"{name}_a")
        self.b = Wire(f"{name}_b")
        self.sum_out = Signal.LOW
        self.carry_out = Signal.LOW
        self._xor_gate = XORGate(name=f"{name}_xor", inputs=[self.a, self.b])
        self._and_gate = ANDGate(name=f"{name}_and", inputs=[self.a, self.b])

    def compute(self, a: Signal, b: Signal) -> tuple[Signal, Signal]:
        self.a.signal = a
        self.a.delay = 0
        self.b.signal = b
        self.b.delay = 0
        self._xor_gate.propagate()
        self._and_gate.propagate()
        self.sum_out = self._xor_gate.output.signal
        self.carry_out = self._and_gate.output.signal
        return (self.sum_out, self.carry_out)

    @property
    def gate_count(self) -> int:
        return self._xor_gate.gate_count + self._and_gate.gate_count

    @property
    def delay(self) -> int:
        return max(self._xor_gate.output.delay, self._and_gate.output.delay)


# ── Full Adder ────────────────────────────────────────────────────────

class FullAdder:
    """Full Adder from two Half Adders and an OR gate."""

    def __init__(self, name: str = "fa"):
        self.name = name
        self.a = Wire(f"{name}_a")
        self.b = Wire(f"{name}_b")
        self.cin = Wire(f"{name}_cin")
        self.sum_out = Signal.LOW
        self.carry_out = Signal.LOW
        self._ha1 = HalfAdder(f"{name}_ha1")
        self._ha2 = HalfAdder(f"{name}_ha2")
        # OR gate wires will be connected during compute
        self._or_carry1 = Wire(f"{name}_c1")
        self._or_carry2 = Wire(f"{name}_c2")
        self._or_gate = ORGate(
            name=f"{name}_or",
            inputs=[self._or_carry1, self._or_carry2],
        )

    def compute(
        self, a: Signal, b: Signal, cin: Signal
    ) -> tuple[Signal, Signal]:
        # ha1: first half-add of a and b
        sum1, carry1 = self._ha1.compute(a, b)
        # ha2: second half-add of sum1 and carry_in
        sum2, carry2 = self._ha2.compute(sum1, cin)
        # carry_out = OR(carry1, carry2)
        self._or_carry1.signal = carry1
        self._or_carry1.delay = self._ha1._and_gate.output.delay
        self._or_carry2.signal = carry2
        self._or_carry2.delay = self._ha2._and_gate.output.delay
        self._or_gate.propagate()
        self.sum_out = sum2
        self.carry_out = self._or_gate.output.signal
        return (self.sum_out, self.carry_out)

    @property
    def gate_count(self) -> int:
        return (
            self._ha1.gate_count
            + self._ha2.gate_count
            + self._or_gate.gate_count
        )

    @property
    def delay(self) -> int:
        return max(
            self._ha2._xor_gate.output.delay,
            self._or_gate.output.delay,
        )


# ── 8-bit Ripple Carry Adder ──────────────────────────────────────────

class RippleCarryAdder8:
    """8-bit Ripple Carry Adder: chains 8 Full Adders."""

    def __init__(self, name: str = "rca8"):
        self.name = name
        self.result: list[Signal] = [Signal.LOW] * 8
        self.carry_out = Signal.LOW
        self._adders = [FullAdder(f"{name}_fa{i}") for i in range(8)]

    def compute(
        self,
        a: list[Signal],
        b: list[Signal],
        cin: Signal = Signal.LOW,
    ) -> tuple[list[Signal], Signal]:
        carry = cin
        self.result = []
        for i in range(8):
            s, carry = self._adders[i].compute(a[i], b[i], carry)
            self.result.append(s)
        self.carry_out = carry
        return (self.result, self.carry_out)

    @property
    def gate_count(self) -> int:
        return sum(fa.gate_count for fa in self._adders)

    @property
    def delay(self) -> int:
        # The delay accumulates through the carry chain
        if self._adders:
            return max(
                self._adders[-1]._ha2._xor_gate.output.delay,
                self._adders[-1]._or_gate.output.delay,
            )
        return 0


# ── 8-bit ALU ─────────────────────────────────────────────────────────

class ALU8:
    """8-bit ALU supporting add, sub, and, or, xor, slt."""

    def __init__(self, name: str = "alu8"):
        self.name = name
        self.result: list[Signal] = [Signal.LOW] * 8
        self.zero_flag: bool = False
        self.carry_flag: bool = False
        self.overflow_flag: bool = False
        self._adder = RippleCarryAdder8(f"{name}_rca")
        # Bitwise gate arrays
        self._and_gates = [
            ANDGate(name=f"{name}_and{i}", inputs=[Wire(f"a{i}"), Wire(f"b{i}")])
            for i in range(8)
        ]
        self._or_gates = [
            ORGate(name=f"{name}_or{i}", inputs=[Wire(f"a{i}"), Wire(f"b{i}")])
            for i in range(8)
        ]
        self._xor_gates = [
            XORGate(name=f"{name}_xor{i}", inputs=[Wire(f"a{i}"), Wire(f"b{i}")])
            for i in range(8)
        ]

    def _int_to_signals(self, value: int, bits: int = 8) -> list[Signal]:
        if value < 0:
            value = (1 << bits) + value
        return [Signal((value >> i) & 1) for i in range(bits)]

    def _signals_to_int(self, signals: list[Signal], signed: bool = True) -> int:
        value = sum(s.value << i for i, s in enumerate(signals))
        if signed and signals[-1] == Signal.HIGH:
            value -= (1 << len(signals))
        return value

    def execute(self, a: int, b: int, op: ALUOp) -> dict:
        a_sigs = self._int_to_signals(a)
        b_sigs = self._int_to_signals(b)

        if op == ALUOp.ADD:
            result_sigs, cout = self._adder.compute(a_sigs, b_sigs, Signal.LOW)
            result_int = self._signals_to_int(result_sigs)
            self.carry_flag = cout == Signal.HIGH
            # Overflow: both operands same sign, result different sign
            a_sign = a_sigs[7].value
            b_sign = b_sigs[7].value
            r_sign = result_sigs[7].value
            self.overflow_flag = (a_sign == b_sign) and (r_sign != a_sign)

        elif op == ALUOp.SUB:
            # a - b = a + ~b + 1
            b_inv = [~s for s in b_sigs]
            result_sigs, cout = self._adder.compute(a_sigs, b_inv, Signal.HIGH)
            result_int = self._signals_to_int(result_sigs)
            self.carry_flag = cout == Signal.HIGH
            a_sign = a_sigs[7].value
            b_inv_sign = b_inv[7].value
            r_sign = result_sigs[7].value
            self.overflow_flag = (a_sign == b_inv_sign) and (r_sign != a_sign)

        elif op == ALUOp.AND:
            result_sigs = []
            for i in range(8):
                self._and_gates[i].inputs[0].signal = a_sigs[i]
                self._and_gates[i].inputs[1].signal = b_sigs[i]
                self._and_gates[i].propagate()
                result_sigs.append(self._and_gates[i].output.signal)
            result_int = self._signals_to_int(result_sigs, signed=False)
            self.carry_flag = False
            self.overflow_flag = False

        elif op == ALUOp.OR:
            result_sigs = []
            for i in range(8):
                self._or_gates[i].inputs[0].signal = a_sigs[i]
                self._or_gates[i].inputs[1].signal = b_sigs[i]
                self._or_gates[i].propagate()
                result_sigs.append(self._or_gates[i].output.signal)
            result_int = self._signals_to_int(result_sigs, signed=False)
            self.carry_flag = False
            self.overflow_flag = False

        elif op == ALUOp.XOR:
            result_sigs = []
            for i in range(8):
                self._xor_gates[i].inputs[0].signal = a_sigs[i]
                self._xor_gates[i].inputs[1].signal = b_sigs[i]
                self._xor_gates[i].propagate()
                result_sigs.append(self._xor_gates[i].output.signal)
            result_int = self._signals_to_int(result_sigs, signed=False)
            self.carry_flag = False
            self.overflow_flag = False

        elif op == ALUOp.SLT:
            # Perform subtraction, check sign bit
            b_inv = [~s for s in b_sigs]
            result_sigs, cout = self._adder.compute(a_sigs, b_inv, Signal.HIGH)
            sub_result = self._signals_to_int(result_sigs)
            # Check for overflow to get correct signed comparison
            a_sign = a_sigs[7].value
            b_inv_sign = b_inv[7].value
            r_sign = result_sigs[7].value
            overflow = (a_sign == b_inv_sign) and (r_sign != a_sign)
            # SLT: 1 if a < b, 0 otherwise
            # With overflow, the sign bit is inverted
            is_negative = (r_sign == 1) != overflow
            slt_val = 1 if is_negative else 0
            result_sigs = self._int_to_signals(slt_val)
            result_int = slt_val
            self.carry_flag = cout == Signal.HIGH
            self.overflow_flag = overflow

        else:
            raise ValueError(f"Unknown ALU operation: {op}")

        self.result = result_sigs
        self.zero_flag = all(s == Signal.LOW for s in result_sigs)

        return {
            "result": result_int,
            "zero": self.zero_flag,
            "carry": self.carry_flag,
            "overflow": self.overflow_flag,
        }


# ── Helper functions ──────────────────────────────────────────────────

def signals_to_str(signals: list[Signal]) -> str:
    return "".join(str(s.value) for s in reversed(signals))

def int_to_bin8(value: int) -> str:
    if value < 0:
        value = (1 << 8) + value
    return format(value & 0xFF, '08b')

