L, H = Signal.LOW, Signal.HIGH


# ── Clock ─────────────────────────────────────────────────────────────

class Clock:
    """Digital clock generator."""

    def __init__(self):
        self.signal: Signal = Signal.LOW
        self.cycle_count: int = 0
        self.edge_count: int = 0
        self._prev_signal: Signal = Signal.LOW
        self._observers: list[Callable[[bool], None]] = []

    @property
    def is_rising_edge(self) -> bool:
        return self._prev_signal == Signal.LOW and self.signal == Signal.HIGH

    @property
    def is_falling_edge(self) -> bool:
        return self._prev_signal == Signal.HIGH and self.signal == Signal.LOW

    def register_observer(self, callback: Callable[[bool], None]) -> None:
        self._observers.append(callback)

    def tick(self) -> None:
        self._prev_signal = self.signal
        if self.signal == Signal.LOW:
            self.signal = Signal.HIGH
            self.edge_count += 1
        else:
            self.signal = Signal.LOW
            self.cycle_count += 1

        rising = self.is_rising_edge
        for observer in self._observers:
            observer(rising)

    def run_cycles(self, n: int) -> None:
        for _ in range(n * 2):
            self.tick()


# ── D Flip-Flop ───────────────────────────────────────────────────────

class DFlipFlop:
    """Edge-triggered D Flip-Flop."""

    def __init__(self, name: str = "dff"):
        self.name = name
        self.d: Signal = Signal.LOW
        self.q: Signal = Signal.LOW
        self.q_bar: Signal = Signal.HIGH

    def on_clock_edge(self, rising: bool) -> None:
        if rising:
            self.q = self.d
            self.q_bar = ~self.d

    def connect_clock(self, clock: Clock) -> None:
        clock.register_observer(self.on_clock_edge)

    def __repr__(self) -> str:
        return f"DFF({self.name}: D={self.d.value}, Q={self.q.value})"


# ── Register ──────────────────────────────────────────────────────────

class Register:
    """N-bit register built from D flip-flops."""

    def __init__(self, width: int, name: str = "reg"):
        self.name = name
        self.width = width
        self.data_in: list[Signal] = [Signal.LOW] * width
        self.data_out: list[Signal] = [Signal.LOW] * width
        self.load_en: bool = False
        self._flip_flops = [DFlipFlop(f"{name}_dff{i}") for i in range(width)]

    def on_clock_edge(self, rising: bool) -> None:
        if rising and self.load_en:
            for i, ff in enumerate(self._flip_flops):
                ff.d = self.data_in[i]
                ff.on_clock_edge(True)
            self.data_out = [ff.q for ff in self._flip_flops]

    def connect_clock(self, clock: Clock) -> None:
        clock.register_observer(self.on_clock_edge)

    def load(self, value: int) -> None:
        for i in range(self.width):
            self.data_in[i] = Signal((value >> i) & 1)
        self.load_en = True

    def read(self) -> int:
        return sum(s.value << i for i, s in enumerate(self.data_out))

    def __repr__(self) -> str:
        val = self.read()
        return f"Register({self.name}: {val}, {self.width}-bit)"


# ── Counter ───────────────────────────────────────────────────────────

class Counter:
    """N-bit counter with wrap-around."""

    def __init__(self, width: int, name: str = "ctr"):
        self.name = name
        self.width = width
        self.max_value = (1 << width) - 1
        self.value: int = 0
        self.wrapped: bool = False

    def on_clock_edge(self, rising: bool) -> None:
        if rising:
            if self.value >= self.max_value:
                self.value = 0
                self.wrapped = True
            else:
                self.value += 1
                self.wrapped = False

    def connect_clock(self, clock: Clock) -> None:
        clock.register_observer(self.on_clock_edge)

    def reset(self) -> None:
        self.value = 0
        self.wrapped = False

    def __repr__(self) -> str:
        return f"Counter({self.name}: {self.value}/{self.max_value})"


# ── Traffic Light FSM ─────────────────────────────────────────────────

class TrafficState(Enum):
    GREEN  = auto()
    YELLOW = auto()
    RED    = auto()
    LEFT_ARROW = auto()


class TrafficOutput:
    def __init__(
        self,
        north_south: str = "RED",
        east_west: str = "RED",
        left_turn: bool = False,
    ):
        self.north_south = north_south
        self.east_west = east_west
        self.left_turn = left_turn

    def __repr__(self) -> str:
        lt = " [LEFT]" if self.left_turn else ""
        return f"NS={self.north_south}, EW={self.east_west}{lt}"

    def __eq__(self, other: object) -> bool:
        if not isinstance(other, TrafficOutput):
            return NotImplemented
        return (
            self.north_south == other.north_south
            and self.east_west == other.east_west
            and self.left_turn == other.left_turn
        )


class TrafficLightFSM:
    """4-state Moore FSM: Traffic Light Controller."""

    STATE_DURATIONS: dict[TrafficState, int] = {
        TrafficState.GREEN:      5,
        TrafficState.YELLOW:     2,
        TrafficState.RED:        5,
        TrafficState.LEFT_ARROW: 3,
    }

    NEXT_STATE: dict[TrafficState, TrafficState] = {
        TrafficState.GREEN:      TrafficState.YELLOW,
        TrafficState.YELLOW:     TrafficState.RED,
        TrafficState.RED:        TrafficState.LEFT_ARROW,
        TrafficState.LEFT_ARROW: TrafficState.GREEN,
    }

    STATE_OUTPUTS: dict[TrafficState, TrafficOutput] = {
        TrafficState.GREEN:      TrafficOutput("GREEN", "RED", False),
        TrafficState.YELLOW:     TrafficOutput("YELLOW", "RED", False),
        TrafficState.RED:        TrafficOutput("RED", "GREEN", False),
        TrafficState.LEFT_ARROW: TrafficOutput("RED", "RED", True),
    }

    def __init__(self, name: str = "traffic_fsm"):
        self.name = name
        self.state: TrafficState = TrafficState.GREEN
        self.state_counter: int = 0
        self.total_cycles: int = 0
        self.transition_log: list[tuple[int, TrafficState, TrafficState]] = []

    def on_clock_edge(self, rising: bool) -> None:
        if rising:
            self.total_cycles += 1
            self.state_counter += 1
            if self.state_counter >= self.STATE_DURATIONS[self.state]:
                old_state = self.state
                self.state = self.NEXT_STATE[self.state]
                self.state_counter = 0
                self.transition_log.append(
                    (self.total_cycles, old_state, self.state)
                )

    def connect_clock(self, clock: Clock) -> None:
        clock.register_observer(self.on_clock_edge)

    @property
    def output(self) -> TrafficOutput:
        return self.STATE_OUTPUTS[self.state]

    @property
    def full_cycle_length(self) -> int:
        return sum(self.STATE_DURATIONS.values())

    def get_state_sequence(self, num_cycles: int) -> list[TrafficState]:
        """Read-only simulation: return state sequence without modifying self."""
        sim_state = TrafficState.GREEN
        sim_counter = 0
        sequence = []
        for _ in range(num_cycles):
            sequence.append(sim_state)
            sim_counter += 1
            if sim_counter >= self.STATE_DURATIONS[sim_state]:
                sim_state = self.NEXT_STATE[sim_state]
                sim_counter = 0
        return sequence

    def __repr__(self) -> str:
        return (
            f"TrafficFSM({self.name}: {self.state.name}, "
            f"counter={self.state_counter}/{self.STATE_DURATIONS[self.state]}, "
            f"cycle={self.total_cycles})"
        )


# ── Circuit Statistics ────────────────────────────────────────────────

def print_circuit_stats(
    name: str,
    gate_count: int,
    delay: int,
    flip_flop_count: int = 0,
) -> dict:
    stats = {
        "name": name,
        "gate_count": gate_count,
        "propagation_delay": delay,
        "flip_flop_count": flip_flop_count,
    }
    print(f"\n{'='*50}")
    print(f"Circuit: {name}")
    print(f"  Primitive gates (NAND): {gate_count}")
    print(f"  Propagation delay:      {delay} gate-delays")
    if flip_flop_count > 0:
        print(f"  Flip-flops:             {flip_flop_count}")
    print(f"{'='*50}")
    return stats
